import * as React from "react"

/**
 * Landing illustrations: wide workflow band, then roadmap strip.
 * Generated by `npm run qa-pr-briefs:image -- --all` (1200x420 PNGs under static/images/qa-pr-briefs/).
 */
const QA_PR_BRIEFS_IMAGES = {
  workflow: `workflow.png`,
  roadmap: `roadmap.png`,
}

function qaPrBriefsImageSrc(fileName) {
  return `${__PATH_PREFIX__}/images/qa-pr-briefs/${fileName}`
}

export function QaPrBriefsLanding({ copy }) {
  const mailHref = `mailto:kontakt@marcinstanek.pl?subject=${encodeURIComponent(
    copy.ctaMailSubject
  )}`
  const { images } = copy

  return (
    <div className="qa-pr-briefs-landing py-4 pb-5">
      <header className="mb-5">
        <h1 className="fs-2 fw-bold mb-3">{copy.h1}</h1>
        <p className="mb-3">{copy.heroLead}</p>
        <p className="text-body-secondary mb-4">{copy.heroSecondary}</p>
        <a href={mailHref} className="btn btn-primary">
          {copy.ctaLabel}
        </a>
      </header>

      <section className="mb-5" aria-labelledby="qa-briefs-problem">
        <h2 id="qa-briefs-problem" className="fs-4 fw-bold mb-3">
          {copy.problemTitle}
        </h2>
        <p className="mb-3">{copy.problemIntro}</p>
        <ul className="mb-0">
          {copy.problemBullets.map((item, i) => (
            <li key={i} className="mb-2">
              {item}
            </li>
          ))}
        </ul>
      </section>

      <figure className="mb-5">
        <img
          className="img-fluid rounded w-100"
          src={qaPrBriefsImageSrc(QA_PR_BRIEFS_IMAGES.workflow)}
          alt={images.workflowAlt}
          width={1200}
          height={420}
          loading="lazy"
          decoding="async"
        />
      </figure>

      <section className="mb-5" aria-labelledby="qa-briefs-offer">
        <h2 id="qa-briefs-offer" className="fs-4 fw-bold mb-3">
          {copy.offerTitle}
        </h2>
        <p className="mb-3">{copy.offerIntro}</p>
        <ul className="mb-3">
          {copy.offerBullets.map((item, i) => (
            <li key={i} className="mb-2">
              {item}
            </li>
          ))}
        </ul>
        <p className="text-body-secondary mb-0">{copy.offerNote}</p>
      </section>

      <section className="mb-5" aria-labelledby="qa-briefs-fit">
        <h2 id="qa-briefs-fit" className="fs-4 fw-bold mb-3">
          {copy.fitTitle}
        </h2>
        <div className="row g-4">
          <div className="col-md-6">
            <p className="fw-semibold mb-3">{copy.fitGoodTitle}</p>
            <ul className="mb-0">
              {copy.fitGoodBullets.map((item, i) => (
                <li key={i} className="mb-2">
                  {item}
                </li>
              ))}
            </ul>
          </div>
          <div className="col-md-6">
            <p className="fw-semibold mb-3">{copy.fitPoorTitle}</p>
            <ul className="mb-0">
              {copy.fitPoorBullets.map((item, i) => (
                <li key={i} className="mb-2">
                  {item}
                </li>
              ))}
            </ul>
          </div>
        </div>
      </section>

      <section className="mb-5" aria-labelledby="qa-briefs-roadmap">
        <h2 id="qa-briefs-roadmap" className="fs-4 fw-bold mb-3">
          {copy.roadmapTitle}
        </h2>
        <p className="mb-4">{copy.roadmapIntro}</p>
        <figure className="mb-4">
          <img
            className="img-fluid rounded w-100"
            src={qaPrBriefsImageSrc(QA_PR_BRIEFS_IMAGES.roadmap)}
            alt={images.roadmapAlt}
            width={1200}
            height={420}
            loading="lazy"
            decoding="async"
          />
        </figure>
        <div className="vstack gap-3">
          {copy.roadmapItems.map((item, i) => (
            <div key={i} className="border rounded p-3 bg-light">
              <h3 className="qa-pr-briefs-roadmap-card__title">{item.title}</h3>
              <p className="mb-0 text-body-secondary">{item.body}</p>
            </div>
          ))}
        </div>
      </section>

      <section className="mb-5" aria-labelledby="qa-briefs-related">
        <h2 id="qa-briefs-related" className="fs-4 fw-bold mb-3">
          {copy.relatedTitle}
        </h2>
        <p className="mb-3">{copy.relatedIntro}</p>
        <ul className="mb-0">
          {copy.relatedPosts.map((post, i) => (
            <li key={i} className="mb-2">
              <a href={post.href}>{post.label}</a>
            </li>
          ))}
        </ul>
      </section>

      <footer className="border-top pt-4">
        <p className="mb-3">{copy.closingLine}</p>
        <a href={mailHref} className="btn btn-outline-primary">
          {copy.ctaLabel}
        </a>
      </footer>
    </div>
  )
}
